        let core_self = xberg::ChunkPlan {
            total_chunks: self.total_chunks,
            chunks: self.chunks.clone().into_iter().map(Into::into).collect(),
            total_estimated_time_ms: self.total_estimated_time_ms as u64,
            use_disk_processing: self.use_disk_processing,
            reason: self.reason.clone().into(),
        };
        core_self.total_pages()
