#[php(name = "Xberg\\ChunkingDecision")]
#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
#[serde(default)]
pub struct ChunkingDecision {
    #[php(prop, name = "type")]
    #[serde(rename = "type")]
    pub type_tag: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub reason: Option<NoChunkingReason>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub chunk: Option<ChunkPlan>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub user_chunks: Option<Vec<PageRange>>,
}

#[php_impl]
impl ChunkingDecision {
    #[php(name = "from_json")]
    pub fn from_json(json: String) -> PhpResult<Self> {
        serde_json::from_str(&json).map_err(|e| PhpException::default(e.to_string()))
    }

    #[php(name = "noChunking")]
    pub fn _factory_no_chunking(reason: &NoChunkingReason) -> Self {
        xberg::ChunkingDecision::NoChunking {
            reason: reason.clone().into(),
        }
        .into()
    }

    #[php(name = "useOverrides")]
    pub fn _factory_use_overrides(userChunks: &ext_php_rs::types::ZendHashTable) -> PhpResult<Self> {
        let mut userChunks_core_result: Vec<xberg::PageRange> = Vec::new();
        for (_, item) in userChunks.iter() {
            if let Some(parsed) = <&PageRange as ext_php_rs::convert::FromZval>::from_zval(item) {
                userChunks_core_result.push(parsed.clone().into());
            } else {
                return Err(ext_php_rs::exception::PhpException::default(
                    "Failed to convert array element to PageRange".to_string(),
                ));
            }
        }
        let userChunks_core: Vec<xberg::PageRange> = userChunks_core_result;
        Ok(xberg::ChunkingDecision::UseOverrides {
            user_chunks: userChunks_core,
        }
        .into())
    }

    #[php(getter)]
    pub fn get_type_tag(&self) -> String {
        self.type_tag.clone()
    }

    #[php(getter)]
    pub fn get_reason(&self) -> Option<NoChunkingReason> {
        self.reason.clone()
    }

    #[php(getter)]
    pub fn get_chunk(&self) -> Option<ChunkPlan> {
        self.chunk.clone()
    }

    #[php(getter)]
    pub fn get_user_chunks(&self) -> Option<Vec<PageRange>> {
        self.user_chunks.clone()
    }
}

