#[php_class]
#[php(name = "Xberg\\ChunkingReason")]
#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
#[serde(default)]
pub struct ChunkingReason {
    #[php(prop, name = "type")]
    #[serde(rename = "type")]
    pub type_tag: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub size_bytes: Option<i64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub threshold_bytes: Option<i64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub page_count: Option<u32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub threshold: Option<u32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub force_ocr: Option<bool>,
}

#[php_impl]
impl ChunkingReason {
    #[php(name = "from_json")]
    pub fn from_json(json: String) -> PhpResult<Self> {
        serde_json::from_str(&json).map_err(|e| PhpException::default(e.to_string()))
    }

    #[php(name = "largeFile")]
    pub fn _factory_large_file(sizeBytes: i64, thresholdBytes: i64) -> Self {
        xberg::ChunkingReason::LargeFile {
            size_bytes: sizeBytes as u64,
            threshold_bytes: thresholdBytes as u64,
        }
        .into()
    }

    #[php(name = "manyPages")]
    pub fn _factory_many_pages(pageCount: u32, threshold: u32) -> Self {
        xberg::ChunkingReason::ManyPages {
            page_count: pageCount,
            threshold,
        }
        .into()
    }

    #[php(name = "ocrRequired")]
    pub fn _factory_ocr_required(pageCount: u32, forceOcr: bool) -> Self {
        xberg::ChunkingReason::OcrRequired {
            page_count: pageCount,
            force_ocr: forceOcr,
        }
        .into()
    }

    #[php(name = "largeAndManyPages")]
    pub fn _factory_large_and_many_pages(sizeBytes: i64, pageCount: u32) -> Self {
        xberg::ChunkingReason::LargeAndManyPages {
            size_bytes: sizeBytes as u64,
            page_count: pageCount,
        }
        .into()
    }

    #[php(getter)]
    pub fn get_type_tag(&self) -> String {
        self.type_tag.clone()
    }

    #[php(getter)]
    pub fn get_size_bytes(&self) -> Option<i64> {
        self.size_bytes
    }

    #[php(getter)]
    pub fn get_threshold_bytes(&self) -> Option<i64> {
        self.threshold_bytes
    }

    #[php(getter)]
    pub fn get_page_count(&self) -> Option<u32> {
        self.page_count
    }

    #[php(getter)]
    pub fn get_threshold(&self) -> Option<u32> {
        self.threshold
    }

    #[php(getter)]
    pub fn get_force_ocr(&self) -> Option<bool> {
        self.force_ocr
    }
}

