    #[cfg(any(feature = "presets", not(feature = "presets")))]
    /// Resolve `(preset, custom_schema_override, context)` into a `ResolvedPreset`.
    ///
    /// - `custom_schema` overrides `preset.schema` when set.
    /// - `context` substitutes `{{key}}` tokens in `preset.context_template`; the
    ///   rendered string is appended to `system_prompt` so the model sees it.
    #[php(name = "resolve")]
    pub fn resolve(
        preset: &Preset,
        customSchema: Option<String>,
        context: HashMap<String, String>,
    ) -> PhpResult<ResolvedPreset> {
        let preset_core: xberg::Preset = preset.clone().into();
        let customSchema_json: Option<serde_json::Value> = customSchema
            .as_deref()
            .map(|s| serde_json::from_str(s).unwrap_or_default());
        let result = xberg::resolve(
            &preset_core,
            customSchema_json,
            &context
                .iter()
                .map(|(k, v)| (k.clone(), v.clone()))
                .collect::<std::collections::BTreeMap<_, _>>(),
        )
        .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result.into())
    }

