#[allow(clippy::useless_conversion)]
impl From<RedactionFinding> for xberg::RedactionFinding {
    fn from(val: RedactionFinding) -> Self {
        Self {
            start: val.start,
            end: val.end,
            category: match val.category.as_str() {
                "email" => xberg::PiiCategory::Email,
                "phone" => xberg::PiiCategory::Phone,
                "ssn" => xberg::PiiCategory::Ssn,
                "credit_card" => xberg::PiiCategory::CreditCard,
                "postal_code" => xberg::PiiCategory::PostalCode,
                "ip_address" => xberg::PiiCategory::IpAddress,
                "iban" => xberg::PiiCategory::Iban,
                "swift_bic" => xberg::PiiCategory::SwiftBic,
                "date_of_birth" => xberg::PiiCategory::DateOfBirth,
                "person" => xberg::PiiCategory::Person,
                "organization" => xberg::PiiCategory::Organization,
                "location" => xberg::PiiCategory::Location,
                "custom" => xberg::PiiCategory::Custom(Default::default()),
                _ => xberg::PiiCategory::Email,
            },
            strategy: match val.strategy.as_str() {
                "mask" => xberg::RedactionStrategy::Mask,
                "hash" => xberg::RedactionStrategy::Hash,
                "token_replace" => xberg::RedactionStrategy::TokenReplace,
                "drop" => xberg::RedactionStrategy::Drop,
                _ => Default::default(),
            },
            replacement_token: val.replacement_token,
        }
    }
}

