/// Convert a `xberg::error::XbergError` error to a PHP exception.
#[allow(dead_code)]
fn xberg_error_to_php_err(e: xberg::error::XbergError) -> ext_php_rs::exception::PhpException {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        xberg::error::XbergError::Io(..) => ext_php_rs::exception::PhpException::default(format!("[Io] {}", msg)),
        xberg::error::XbergError::Parsing { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Parsing] {}", msg))
        }
        xberg::error::XbergError::Ocr { .. } => ext_php_rs::exception::PhpException::default(format!("[Ocr] {}", msg)),
        xberg::error::XbergError::Validation { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Validation] {}", msg))
        }
        xberg::error::XbergError::Cache { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Cache] {}", msg))
        }
        xberg::error::XbergError::ImageProcessing { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[ImageProcessing] {}", msg))
        }
        xberg::error::XbergError::Serialization { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Serialization] {}", msg))
        }
        xberg::error::XbergError::MissingDependency(..) => {
            ext_php_rs::exception::PhpException::default(format!("[MissingDependency] {}", msg))
        }
        xberg::error::XbergError::Plugin { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Plugin] {}", msg))
        }
        xberg::error::XbergError::LockPoisoned(..) => {
            ext_php_rs::exception::PhpException::default(format!("[LockPoisoned] {}", msg))
        }
        xberg::error::XbergError::UnsupportedFormat(..) => {
            ext_php_rs::exception::PhpException::default(format!("[UnsupportedFormat] {}", msg))
        }
        xberg::error::XbergError::Embedding { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Embedding] {}", msg))
        }
        xberg::error::XbergError::Reranking { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Reranking] {}", msg))
        }
        xberg::error::XbergError::Transcription { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Transcription] {}", msg))
        }
        xberg::error::XbergError::Timeout { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Timeout] {}", msg))
        }
        xberg::error::XbergError::Cancelled => {
            ext_php_rs::exception::PhpException::default(format!("[Cancelled] {}", msg))
        }
        xberg::error::XbergError::Security { .. } => {
            ext_php_rs::exception::PhpException::default(format!("[Security] {}", msg))
        }
        xberg::error::XbergError::Other(..) => ext_php_rs::exception::PhpException::default(format!("[Other] {}", msg)),
        _ => ext_php_rs::exception::PhpException::default(msg),
    }
}

